   209	    private static S3Checksum buildChecksum(byte[] data, List<Part> parts, boolean multipartUpload) {
   210	        S3Checksum checksum = new S3Checksum();
   211	        checksum.setChecksumSHA1(S3Checksum.sha1Base64(data));
   212	        checksum.setChecksumSHA256(S3Checksum.sha256Base64(data));
   213	        checksum.setChecksumType(multipartUpload || (parts != null && parts.size() > 1)
   214	                ? "COMPOSITE"
   215	                : "FULL_OBJECT");
   216	        return checksum;
   217	    }
